/**
 * Date Formatting Utility
 *
 * Formats ISO 8601 date strings into human-readable format.
 * Uses native JavaScript Intl.DateTimeFormat (no external libraries).
 */

/**
 * Formats a date string to "Month Day, Year" format
 *
 * @param dateString - ISO 8601 date string or null/undefined
 * @returns Formatted date string or "N/A" if invalid
 *
 * @example
 * formatDate("2025-01-15T10:30:00.000Z") // "January 15, 2025"
 * formatDate(null) // "N/A"
 * formatDate("invalid-date") // "N/A"
 */
export function formatDate(dateString: string | null | undefined): string {
  if (!dateString) {
    return 'N/A';
  }

  try {
    const date = new Date(dateString);

    // Check for Invalid Date
    if (isNaN(date.getTime())) {
      console.warn(`Invalid date string: ${dateString}`);
      return 'N/A';
    }

    // Format using Intl.DateTimeFormat (locale: en-US)
    return new Intl.DateTimeFormat('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    }).format(date);
  } catch (error) {
    console.error('Date formatting error:', error);
    return 'N/A';
  }
}
