/**
 * DashboardPage Component
 *
 * 認証されたユーザー専用のダッシュボードページ。
 * ユーザー情報の表示を提供します。
 *
 * ルート: /dashboard
 */

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import type { User } from '../types/auth';
import { LoadingSpinner, ErrorMessage, ProfileCard, PasswordCard } from '../components';

/**
 * DashboardPageコンポーネント
 * 認証されたユーザーのダッシュボードを提供します
 */
const DashboardPage: React.FC = () => {
  const navigate = useNavigate();
  const { getProfile } = useAuth();
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  /**
   * ユーザープロフィールを取得
   */
  useEffect(() => {
    const fetchProfile = async () => {
      try {
        const profile = await getProfile();
        setUser(profile);
      } catch (err) {
        setError('Failed to load user profile. Please login again.');
        // 認証エラーの場合はログインページへ
        setTimeout(() => {
          navigate('/login', { replace: true });
        }, 2000);
      } finally {
        setIsLoading(false);
      }
    };

    fetchProfile();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [navigate]);

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-20">
        <LoadingSpinner size="large" text="Loading your profile..." />
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex items-center justify-center p-4 py-20">
        <div className="max-w-md w-full">
          <ErrorMessage message={error} variant="error" />
        </div>
      </div>
    );
  }

  if (!user) {
    return null;
  }

  /**
   * プロフィール更新成功時のコールバック
   * 更新されたユーザー情報で状態を更新
   */
  const handleProfileUpdateSuccess = (updatedUser: User) => {
    setUser(updatedUser);
  };

  return (
    <main className="max-w-7xl mx-auto py-6 sm:px-6 lg:px-8">
      <div className="px-4 py-6 sm:px-0">
        {/* Profile Card with Inline Editing (US5 + spec 017) */}
        <div className="mb-6">
          <ProfileCard user={user} onProfileUpdate={handleProfileUpdateSuccess} />
        </div>

        {/* Password Card with Inline Password Change */}
        <div className="mb-6">
          <PasswordCard userEmail={user.email} />
        </div>
      </div>
    </main>
  );
};

export default DashboardPage;
