/**
 * ProfileCard Component with Inline Editing
 *
 * ユーザープロフィール情報を表示し、インライン編集機能を提供するカードコンポーネント。
 *
 * 機能:
 * - プロフィール情報の表示（Name、Email、Member Since、Last Updated）
 * - インライン編集機能（Email・Name）
 * - 編集時のバリデーションとエラーハンドリング
 * - 成功/エラーメッセージの表示
 *
 * spec 017: プロフィール更新API統合
 */

import React, { useState } from 'react';
import { formatDate } from '../utils/dateFormatter';
import type { User } from '../types/auth';
import { useAuth } from '../hooks/useAuth';
import { LoadingSpinner, ErrorMessage } from './';

export interface ProfileCardProps {
  user: User;
  className?: string;
  onProfileUpdate?: (updatedUser: User) => void;
}

const ProfileCard: React.FC<ProfileCardProps> = ({ user, className = '', onProfileUpdate }) => {
  const { updateProfile } = useAuth();
  const [isEditing, setIsEditing] = useState(false);
  const [email, setEmail] = useState(user.email || '');
  const [name, setName] = useState(user.name || '');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  const handleEdit = () => {
    setIsEditing(true);
    setError(null);
    setSuccessMessage(null);
  };

  const handleCancel = () => {
    setIsEditing(false);
    setEmail(user.email || '');
    setName(user.name || '');
    setError(null);
    setSuccessMessage(null);
  };

  const handleSave = async () => {
    setError(null);
    setSuccessMessage(null);

    // 変更がない場合
    if (email === user.email && name === (user.name || '')) {
      setError('No changes to save');
      return;
    }

    setIsLoading(true);

    try {
      const updateData: { email?: string; name?: string } = {};

      // 変更があったフィールドのみ送信
      if (email !== user.email) {
        updateData.email = email.trim();
      }
      if (name !== (user.name || '')) {
        updateData.name = name.trim();
      }

      const updatedUser = await updateProfile(updateData);
      setSuccessMessage('Profile updated successfully!');
      setIsEditing(false);

      // 親コンポーネントに通知
      if (onProfileUpdate) {
        onProfileUpdate(updatedUser);
      }
    } catch (err) {
      if (err instanceof Error) {
        if (err.message.includes('already in use') || err.message.includes('Conflict')) {
          setError('Email address is already in use by another user');
        } else if (err.message.includes('Bad Request') || err.message.includes('validation')) {
          setError('Invalid input. Please check your email and name');
        } else {
          setError(err.message || 'Failed to update profile');
        }
      } else {
        setError('An unexpected error occurred');
      }
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className={`bg-white rounded-lg shadow-md p-6 ${className}`}>
      {/* Header: アバター + タイトル + Edit Button */}
      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center space-x-4">
          <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center">
            <span className="text-2xl font-bold text-blue-600">
              {user.email.charAt(0).toUpperCase()}
            </span>
          </div>
          <div>
            <h2 className="text-2xl font-bold text-gray-800">Profile</h2>
          </div>
        </div>

        {/* Edit/Save/Cancel Buttons */}
        {!isEditing ? (
          <button
            onClick={handleEdit}
            className="px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-colors"
          >
            Edit Profile
          </button>
        ) : (
          <div className="flex gap-2">
            <button
              onClick={handleCancel}
              disabled={isLoading}
              className="px-4 py-2 bg-gray-200 text-gray-700 rounded-md hover:bg-gray-300 focus:outline-none focus:ring-2 focus:ring-gray-500 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
            >
              Cancel
            </button>
            <button
              onClick={handleSave}
              disabled={isLoading}
              className="px-4 py-2 bg-green-600 text-white rounded-md hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-green-500 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2 transition-colors"
            >
              {isLoading && <LoadingSpinner size="small" />}
              {isLoading ? 'Saving...' : 'Save'}
            </button>
          </div>
        )}
      </div>

      {/* Messages */}
      {error && <ErrorMessage message={error} variant="error" className="mb-4" />}
      {successMessage && (
        <ErrorMessage message={successMessage} variant="success" className="mb-4" />
      )}

      {/* プロフィール情報 (FR-014: 各フィールドを1回のみ表示) */}
      <div className="space-y-4">
        {/* Name */}
        <div className="border-b border-gray-200 pb-4">
          <label className="block text-sm font-medium text-gray-500 mb-1">Name</label>
          {!isEditing ? (
            <p className="text-base text-gray-800">{user.name || '(Not set)'}</p>
          ) : (
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="Your Name"
              disabled={isLoading}
              maxLength={100}
            />
          )}
        </div>

        {/* Email */}
        <div className="border-b border-gray-200 pb-4">
          <label className="block text-sm font-medium text-gray-500 mb-1">Email Address</label>
          {!isEditing ? (
            <p className="text-base text-gray-800">{user.email}</p>
          ) : (
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="your.email@example.com"
              disabled={isLoading}
              maxLength={254}
            />
          )}
        </div>

        {/* Member Since (read-only) */}
        <div className="border-b border-gray-200 pb-4">
          <label className="block text-sm font-medium text-gray-500 mb-1">Member Since</label>
          <p className="text-base text-gray-800">{formatDate(user.createdAt)}</p>
        </div>

        {/* Last Updated (read-only) */}
        <div>
          <label className="block text-sm font-medium text-gray-500 mb-1">Last Updated</label>
          <p className="text-base text-gray-800">{formatDate(user.updatedAt)}</p>
        </div>
      </div>
    </div>
  );
};

export default ProfileCard;
